// Escape HTML to prevent XSS in inline page templates
function escapeHtml(str) {
  if (str == null) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/'/g, '&#39;')
    .replace(/'/g, '&#x27;')
    .replace(/'/g, '&quot;');
}

