// ============================================================
// UTM LINK BUILDER
// ============================================================

/**
 * Build an outbound URL with standardized UTM tracking parameters.
 * @param {string} baseUrl - e.g. 'https://cutthelock.com'
 * @param {string} path - e.g. '/listings' or '/listing/123'
 * @param {string} source - utm_source: meta, email, blog, print, twitter
 * @param {string} medium - utm_medium: paid, outreach, organic, social, newsletter
 * @param {string} campaign - utm_campaign: descriptive slug, e.g. 'new_listings', 'recovery_ad_apr26'
 * @param {string} [content] - optional utm_content for A/B variant tracking
 * @returns {string} URL with UTM query params
 */
function utmLink(baseUrl, path, source, medium, campaign, content) {
  const params = new URLSearchParams({
    utm_source: source,
    utm_medium: medium,
    utm_campaign: campaign,
    ...(content ? { utm_content: content } : {})
  });
  return `${baseUrl.replace(/\/$/, '')}${path}?${params.toString()}`;
}

