function escHtml(str) {
  if (!str) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function postmarkOrRelay({ subject, textBody, htmlBody }) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      from: FROM_EMAIL,
      to: ADMIN_EMAIL,
      subject,
      text: textBody,
      html: htmlBody
    });

    const url = new URL(`${STORAGE_BASE_URL}/api/email/send`);
    const options = {
      hostname: url.hostname,
      port: url.port || 443,
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload),
        'Authorization': `Bearer ${PLATFORM_API_TOKEN}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          resolve(true);
        } else {
          console.warn(`[Email] Relay returned ${res.statusCode}: ${data}`);
          resolve(false);
        }
      });
    });

    req.on('error', reject);
    req.setTimeout(8000, () => { req.destroy(new Error('Email relay timeout')); });
    req.write(payload);
    req.end();
  });
}

/**
 * Send email to an arbitrary recipient via the configured external relay.
 * Returns true if sent, false if relay failed/unavailable.
 */
function sendEmailViaRelay({ to, subject, textBody, htmlBody }) {
  if (!PLATFORM_API_TOKEN) return Promise.resolve(false);
  return new Promise((resolve) => {
    const payload = JSON.stringify({
      from: FROM_EMAIL,
      to,
      subject,
      text: textBody,
      html: htmlBody
    });

    const url = new URL(`${STORAGE_BASE_URL}/api/email/send`);
    const options = {
      hostname: url.hostname,
      port: url.port || 443,
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload),
        'Authorization': `Bearer ${PLATFORM_API_TOKEN}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          resolve(true);
        } else {
          console.warn(`[Email] Relay ${to} returned ${res.statusCode}: ${data}`);
          resolve(false);
        }
      });
    });

    req.on('error', (e) => { console.warn('[Email] Relay error:', e.message); resolve(false); });
    req.setTimeout(10000, () => { req.destroy(new Error('timeout')); resolve(false); });
    req.write(payload);
    req.end();
  });
}

