async function saveNotification(pool, { type, recipient, subject, body, metadata }) {
  try {
    await pool.query(
      `INSERT INTO notifications (type, recipient, subject, body, metadata, sent_at)
       VALUES ($1, $2, $3, $4, $5, NOW())`,
      [type, recipient, subject || null, body || null, metadata ? JSON.stringify(metadata) : null]
    );
  } catch (e) {
    // Best-effort — don't crash if table doesn't exist yet
    console.warn('[Email] Could not save notification to DB:', e.message);
  }
}

// ============================================================
// R2 PHOTO UPLOAD HELPER
// ============================================================

/**
 * Upload a Buffer to external storage proxy. Returns URL string.
 */
function uploadToR2(buffer, filename, mimeType) {
  return new Promise((resolve, reject) => {
    if (!PLATFORM_API_TOKEN) {
      return reject(new Error('No storage API token configured'));
    }

    const boundary = '----R2Boundary' + Date.now() + Math.random().toString(36).slice(2);
    const safeName = (filename || 'photo.jpg').replace(/[^a-zA-Z0-9._-]/g, '_');

    const headerBuf = Buffer.from(
      `--${boundary}\r\n` +
      `Content-Disposition: form-data; name="file"; filename="${safeName}"\r\n` +
      `Content-Type: ${mimeType || 'image/jpeg'}\r\n\r\n`
    );
    const footerBuf = Buffer.from(`\r\n--${boundary}--\r\n`);
    const body = Buffer.concat([headerBuf, buffer, footerBuf]);

    const uploadUrl = new URL(`${STORAGE_BASE_URL}/api/proxy/r2/upload`);
    const options = {
      hostname: uploadUrl.hostname,
      port: uploadUrl.port || 443,
      path: uploadUrl.pathname + (uploadUrl.search || ''),
      method: 'POST',
      headers: {
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'Content-Length': body.length,
        'Authorization': `Bearer ${PLATFORM_API_TOKEN}`
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => { data += chunk; });
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (res.statusCode >= 200 && res.statusCode < 300) {
            const url = parsed.url || parsed.publicUrl || parsed.cdnUrl || (parsed.file && parsed.file.url);
            if (url) {
              resolve(url);
            } else {
              reject(new Error(`R2 upload: no URL in response: ${data}`));
            }
          } else {
            reject(new Error(`R2 upload HTTP ${res.statusCode}: ${data}`));
          }
        } catch (e) {
          reject(new Error(`R2 response parse error: ${data}`));
        }
      });
    });

    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(new Error('R2 upload timeout')); });
    req.write(body);
    req.end();
  });
}

