const ADMIN_PASSWORD = (process.env.ADMIN_PASSWORD || 'CTL2026').trim();

function requireAdmin(req, res, next) {
  const pw = String(req.headers['x-admin-password'] || req.query._pw || '').trim();
  if (!pw || pw !== ADMIN_PASSWORD) {
    return res.status(401).json({ success: false, message: 'Unauthorized' });
  }
  next();
}

// No-cache headers for HTML
app.use((req, res, next) => {
  if (req.accepts('html') && !req.path.startsWith('/api/')) {
    res.set('Cache-Control', 'no-cache, no-store, must-revalidate');
  }
  next();
});

// Ensure generated HTML surfaces share the refreshed public theme.
// Many admin/document routes are inline templates rather than pageShell output.
app.use((req, res, next) => {
  const originalSend = res.send.bind(res);
  res.send = function themedSend(body) {
    const contentType = String(res.get('Content-Type') || '');
    const isHtml = contentType.includes('text/html') || (typeof body === 'string' && /^\s*<!DOCTYPE html/i.test(body));
    if (isHtml && typeof body === 'string' && !body.includes('href="/styles.css"') && body.includes('</head>')) {
      body = body.replace('</head>', '    <link rel="stylesheet" href="/styles.css">\n</head>');
    }
    return originalSend(body);
  };
  next();
});

// ============================================================
// LISTING VIEW TRACKING
// ============================================================

/**
 * Track a listing page view. Deduplicates within a 30-minute window
 * per IP+UA hash so refreshes and bot crawls don't inflate counts.
 * Fire-and-forget — never blocks the HTTP response.
 */
async function trackListingView(listingId, req) {
  try {
    const rawIp = req.ip || (req.connection && req.connection.remoteAddress) || '';
    const ua = req.get('User-Agent') || '';
    const ipHash = crypto.createHash('sha256').update(rawIp + ua).digest('hex');

    // Skip if same visitor already counted in the last 30 minutes
    const recent = await pool.query(
      `SELECT 1 FROM listing_views
       WHERE listing_id = $1 AND ip_hash = $2
         AND viewed_at > NOW() - INTERVAL '30 minutes'
       LIMIT 1`,
      [listingId, ipHash]
    );

    if (recent.rows.length === 0) {
      await pool.query(
        `INSERT INTO listing_views (listing_id, ip_hash) VALUES ($1, $2)`,
        [listingId, ipHash]
      );
      await pool.query(
        `UPDATE listings SET view_count = COALESCE(view_count, 0) + 1 WHERE id = $1`,
        [listingId]
      );
    }
  } catch (e) {
    // Non-fatal — view tracking failure must never break the page
  }
}

