// Track conversion events from the browser (buy clicks, form submits, etc.)
app.post('/api/events', (req, res) => {
  try {
    const { event_type, path: evPath, referrer, utm_source, utm_medium, utm_campaign, metadata } = req.body || {};
    const allowed = ['buy_click', 'purchase', 'recovery_submit', 'email_signup', 'page_view', 'checkout_initiated', 'checkout_completed'];
    if (!event_type || !allowed.includes(event_type)) {
      return res.status(400).json({ success: false, message: 'Invalid event_type.' });
    }

    const ip = req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.socket?.remoteAddress || '';
    const ua = req.headers['user-agent'] || '';

    trackEvent(event_type, {
      path: (evPath || '').slice(0, 500) || null,
      referrer: (referrer || '').slice(0, 500) || null,
      utm_source: (utm_source || '').slice(0, 255) || null,
      utm_medium: (utm_medium || '').slice(0, 255) || null,
      utm_campaign: (utm_campaign || '').slice(0, 255) || null,
      user_agent_hash: hashValue(ua),
      ip_hash: hashValue(ip),
      metadata: metadata || null
    });

    res.json({ success: true });
  } catch (err) {
    // Never fail the client — analytics is best-effort
    res.json({ success: true });
  }
});

