// ============================================================
// ANALYTICS HELPERS
// ============================================================

function hashValue(val) {
  if (!val) return null;
  return crypto.createHash('sha256').update(String(val)).digest('hex').slice(0, 64);
}

/**
 * Fire-and-forget analytics insert. Never throws, never blocks.
 */
function trackEvent(eventType, data) {
  setImmediate(() => {
    pool.query(
      `INSERT INTO analytics_events
         (event_type, path, referrer, utm_source, utm_medium, utm_campaign, user_agent_hash, ip_hash, metadata)
       VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)`,
      [
        eventType,
        data.path || null,
        data.referrer || null,
        data.utm_source || null,
        data.utm_medium || null,
        data.utm_campaign || null,
        data.user_agent_hash || null,
        data.ip_hash || null,
        data.metadata ? JSON.stringify(data.metadata) : null
      ]
    ).catch(e => {
      // Silently ignore — analytics failures should never impact user requests
      if (!e.message.includes('does not exist')) {
        console.warn('[Analytics] insert failed:', e.message);
      }
    });
  });
}

// Page-view middleware: log every GET to a non-API, non-static path
// Excludes bot probes (WordPress, PHP scanners) and static assets
app.use((req, res, next) => {
  if (
    req.method === 'GET' &&
    !req.path.startsWith('/api/') &&
    !req.path.startsWith('/health') &&
    !req.path.startsWith('/wp-admin') &&
    !req.path.startsWith('/wordpress') &&
    !/\.(css|js|ico|png|jpg|jpeg|gif|svg|woff|woff2|ttf|map|webp|php|xml|txt)$/i.test(req.path)
  ) {
    const ip = req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.socket?.remoteAddress || '';
    const ua = req.headers['user-agent'] || '';
    const referrer = req.headers['referer'] || req.headers['referrer'] || '';
    const qs = req.query;
    trackEvent('page_view', {
      path: req.path,
      referrer: referrer.slice(0, 500) || null,
      utm_source: (qs.utm_source || '').slice(0, 255) || null,
      utm_medium: (qs.utm_medium || '').slice(0, 255) || null,
      utm_campaign: (qs.utm_campaign || '').slice(0, 255) || null,
      user_agent_hash: hashValue(ua),
      ip_hash: hashValue(ip)
    });
  }
  next();
});

