// Get all listings (public marketplace)
app.get('/api/listings', async (req, res) => {
  try {
    const { category, status, sort = 'newest', search, page = 1, limit = 20 } = req.query;
    const offset = (parseInt(page) - 1) * parseInt(limit);

    // Include trending signal: listings with 10+ views in the last 48 hours
    let query = `SELECT l.*, (COALESCE(t.recent_views, 0) >= 10) AS is_trending
FROM listings l
LEFT JOIN (
  SELECT listing_id, COUNT(*) AS recent_views
  FROM listing_views
  WHERE viewed_at > NOW() - INTERVAL '48 hours'
  GROUP BY listing_id
) t ON l.id = t.listing_id`;
    const conditions = [];
    const params = [];

    // Default: show available items. Also allow 'all' to see sold items too.
    if (status && status !== 'all') {
      params.push(status);
      conditions.push(`status = $${params.length}`);
    } else if (!status) {
      // Show active/available and sold items (marketplace browse)
      params.push('active');
      params.push('available');
      params.push('sold');
      conditions.push(`status IN ($${params.length - 2}, $${params.length - 1}, $${params.length})`);
    }
    if (category) {
      params.push(category);
      conditions.push(`category = $${params.length}`);
    }
    if (search && search.trim()) {
      params.push(`%${search.trim()}%`);
      conditions.push(`(title ILIKE $${params.length} OR description ILIKE $${params.length} OR category ILIKE $${params.length})`);
    }

    if (conditions.length > 0) {
      query += ' WHERE ' + conditions.join(' AND ');
    }

    if (sort === 'price_low') {
      query += " ORDER BY (CASE WHEN status IN ('active', 'available') THEN 0 ELSE 1 END), price ASC";
    } else if (sort === 'price_high') {
      query += " ORDER BY (CASE WHEN status IN ('active', 'available') THEN 0 ELSE 1 END), price DESC";
    } else {
      // Default: Tier 1 sentimental items surface first (recovery priority), then featured, then newest
      query += " ORDER BY (CASE WHEN status IN ('active', 'available') THEN 0 ELSE 1 END), (CASE WHEN is_sentimental = true AND sentimental_tier = 1 THEN 0 ELSE 1 END), featured DESC, created_at DESC";
    }

    // Save condition params before adding LIMIT/OFFSET
    const conditionParams = params.slice();

    params.push(parseInt(limit));
    query += ` LIMIT $${params.length}`;
    params.push(offset);
    query += ` OFFSET $${params.length}`;

    const result = await pool.query(query, params);

    // Total count (uses only the condition params, not LIMIT/OFFSET)
    let countQuery = 'SELECT COUNT(*) FROM listings';
    if (conditions.length > 0) {
      countQuery += ' WHERE ' + conditions.join(' AND ');
    }
    const countResult = await pool.query(countQuery, conditionParams);

    res.json({ success: true, listings: result.rows, total: parseInt(countResult.rows[0].count) });
  } catch (err) {
    console.error('Error fetching listings:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch listings.' });
  }
});

