// GET /api/admin/analytics/summary?days=7|30
app.get('/api/admin/analytics/summary', requireAdmin, async (req, res) => {
  try {
    const days = Math.min(parseInt(req.query.days) || 7, 90);

    // Daily page views + unique visitors
    const dailyRows = await pool.query(`
      SELECT
        DATE(created_at) AS day,
        COUNT(*) FILTER (WHERE event_type = 'page_view') AS page_views,
        COUNT(DISTINCT ip_hash) FILTER (WHERE event_type = 'page_view' AND ip_hash IS NOT NULL) AS unique_visitors
      FROM analytics_events
      WHERE created_at >= NOW() - ($1 || ' days')::INTERVAL
      GROUP BY DATE(created_at)
      ORDER BY day DESC
    `, [days]);

    // Total summary
    const totalRows = await pool.query(`
      SELECT
        COUNT(*) FILTER (WHERE event_type = 'page_view') AS total_page_views,
        COUNT(DISTINCT ip_hash) FILTER (WHERE event_type = 'page_view' AND ip_hash IS NOT NULL) AS total_unique_visitors,
        COUNT(*) FILTER (WHERE event_type = 'recovery_submit') AS recovery_submits,
        COUNT(*) FILTER (WHERE event_type = 'email_signup') AS email_signups,
        COUNT(*) FILTER (WHERE event_type = 'buy_click') AS buy_clicks,
        COUNT(*) FILTER (WHERE event_type = 'purchase') AS purchases,
        COUNT(*) FILTER (WHERE event_type = 'checkout_initiated') AS checkout_initiated,
        COUNT(*) FILTER (WHERE event_type = 'checkout_completed') AS checkout_completed
      FROM analytics_events
      WHERE created_at >= NOW() - ($1 || ' days')::INTERVAL
    `, [days]);

    // Top pages
    const topPages = await pool.query(`
      SELECT path, COUNT(*) AS views
      FROM analytics_events
      WHERE event_type = 'page_view'
        AND path IS NOT NULL
        AND created_at >= NOW() - ($1 || ' days')::INTERVAL
      GROUP BY path
      ORDER BY views DESC
      LIMIT 10
    `, [days]);

    // Top referrers (non-empty, non-self)
    const topReferrers = await pool.query(`
      SELECT referrer, COUNT(*) AS visits
      FROM analytics_events
      WHERE event_type = 'page_view'
        AND referrer IS NOT NULL
        AND referrer != ''
        AND referrer NOT LIKE '%cutthelock.com%'
        AND created_at >= NOW() - ($1 || ' days')::INTERVAL
      GROUP BY referrer
      ORDER BY visits DESC
      LIMIT 10
    `, [days]);

    // Top UTM sources
    const topUtmSources = await pool.query(`
      SELECT utm_source, utm_medium, utm_campaign, COUNT(*) AS hits
      FROM analytics_events
      WHERE utm_source IS NOT NULL
        AND created_at >= NOW() - ($1 || ' days')::INTERVAL
      GROUP BY utm_source, utm_medium, utm_campaign
      ORDER BY hits DESC
      LIMIT 10
    `, [days]);

    res.json({
      success: true,
      days,
      summary: totalRows.rows[0],
      daily: dailyRows.rows,
      top_pages: topPages.rows,
      top_referrers: topReferrers.rows,
      top_utm_sources: topUtmSources.rows
    });
  } catch (err) {
    console.error('Error fetching analytics summary:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch analytics.' });
  }
});

