// Admin: get all recovery claims
app.get('/api/admin/claims', requireAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 50, search = '' } = req.query;
    const offset = (parseInt(page) - 1) * parseInt(limit);

    let conditions = [];
    let params = [];

    if (search) {
      params.push(`%${search}%`);
      conditions.push(`(
        reporter_name ILIKE $${params.length} OR
        item_name ILIKE $${params.length} OR
        item_description ILIKE $${params.length} OR
        reporter_email ILIKE $${params.length} OR
        facility_name ILIKE $${params.length}
      )`);
    }

    const where = conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : '';

    const countResult = await pool.query(
      `SELECT COUNT(*) FROM lost_items ${where}`,
      params
    );

    params.push(parseInt(limit));
    params.push(offset);

    const result = await pool.query(
      `SELECT
        li.id, li.reporter_name, li.reporter_email, li.reporter_phone,
        li.item_name, li.item_description, li.category, li.status,
        li.facility_name, li.facility_city, li.facility_state, li.unit_number,
        li.date_lost::text, li.photos,
        li.created_at,
        li.recovery_item_id,
        ri.photo_url AS recovery_item_photo,
        ri.title AS recovery_item_title,
        ri.description AS recovery_item_description,
        ri.status AS recovery_item_status,
        (SELECT json_build_object(
          'id_verification', COUNT(*) FILTER (WHERE cd.document_type = 'id_verification'),
          'agreement', COUNT(*) FILTER (WHERE cd.document_type = 'agreement'),
          'total', COUNT(*)
        ) FROM claim_documents cd WHERE cd.claim_id = li.id) AS doc_summary
       FROM lost_items li
       LEFT JOIN recovery_items ri ON ri.id = li.recovery_item_id
       ${where}
       ORDER BY li.created_at DESC
       LIMIT $${params.length - 1} OFFSET $${params.length}`,
      params
    );

    res.json({
      success: true,
      claims: result.rows,
      total: parseInt(countResult.rows[0].count),
      page: parseInt(page),
      limit: parseInt(limit)
    });
  } catch (err) {
    console.error('Error fetching admin claims:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch claims.' });
  }
});

// Admin: update claim status
app.patch('/api/admin/claims/:id/status', requireAdmin, async (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    if (isNaN(id) || id <= 0) return res.status(400).json({ success: false, message: 'Invalid claim ID.' });

    const { status } = req.body;
    const allowed = ['new', 'reviewing', 'matched', 'returned', 'closed', 'open'];
    if (!status || !allowed.includes(status)) {
      return res.status(400).json({ success: false, message: 'Status must be one of: new, reviewing, matched, returned, closed.' });
    }

    const result = await pool.query(
      `UPDATE lost_items SET status=$1, updated_at=NOW() WHERE id=$2 RETURNING id, status`,
      [status, id]
    );

    if (result.rows.length === 0) return res.status(404).json({ success: false, message: 'Claim not found.' });

    res.json({ success: true, claim: result.rows[0] });
  } catch (err) {
    console.error('Error updating claim status:', err);
    res.status(500).json({ success: false, message: 'Failed to update status.' });
  }
});

