// Admin: upload a document to a recovery claim
app.post('/api/admin/claims/:id/documents', requireAdmin, async (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    if (isNaN(id) || id <= 0) return res.status(400).json({ success: false, message: 'Invalid claim ID.' });

    const { dataUrl, filename, document_type } = req.body;
    if (!dataUrl || typeof dataUrl !== 'string') {
      return res.status(400).json({ success: false, message: 'dataUrl is required.' });
    }

    const validTypes = ['id_verification', 'agreement', 'other'];
    const docType = validTypes.includes(document_type) ? document_type : 'other';

    // Verify claim exists
    const claimCheck = await pool.query('SELECT id FROM lost_items WHERE id=$1', [id]);
    if (claimCheck.rows.length === 0) return res.status(404).json({ success: false, message: 'Claim not found.' });

    // Parse data URL
    const match = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
    if (!match) return res.status(400).json({ success: false, message: 'Invalid data URL format.' });

    const mimeType = match[1];
    const base64Data = match[2];
    const buffer = Buffer.from(base64Data, 'base64');

    // 10MB limit
    if (buffer.length > 10 * 1024 * 1024) {
      return res.status(400).json({ success: false, message: 'File too large (max 10MB).' });
    }

    const allowedMimes = ['application/pdf', 'image/jpeg', 'image/png', 'image/webp'];
    if (!allowedMimes.includes(mimeType)) {
      return res.status(400).json({ success: false, message: 'Invalid file type. Allowed: PDF, JPG, PNG.' });
    }

    const extMap = { 'application/pdf': 'pdf', 'image/jpeg': 'jpg', 'image/png': 'png', 'image/webp': 'webp' };
    const ext = extMap[mimeType] || 'bin';
    const safeName = filename
      ? filename.replace(/[^a-zA-Z0-9._-]/g, '_')
      : `claim-${id}-${docType}-${Date.now()}.${ext}`;

    let fileUrl = dataUrl;
    try {
      fileUrl = await uploadToR2(buffer, safeName, mimeType);
      console.log(`[R2] Uploaded claim doc: ${safeName} → ${fileUrl}`);
    } catch (uploadErr) {
      console.warn('[R2] Claim doc upload failed, using base64 fallback:', uploadErr.message);
    }

    const insertResult = await pool.query(
      `INSERT INTO claim_documents (claim_id, document_type, filename, file_url, file_size, mime_type)
       VALUES ($1, $2, $3, $4, $5, $6) RETURNING *`,
      [id, docType, safeName, fileUrl, buffer.length, mimeType]
    );
    res.json({ success: true, document: insertResult.rows[0] });
  } catch (err) {
    console.error('Error uploading claim document:', err);
    res.status(500).json({ success: false, message: 'Upload failed.' });
  }
});

