// ============================================================
// SUBSCRIBER NOTIFICATION ENGINE
// ============================================================

const NOTIFY_BATCH_LIMIT = 50; // max emails per notification event

/**
 * Fire-and-forget: send new-listing emails to eligible subscribers.
 * @param {number[]} listingIds - IDs of available listings to feature in the email.
 *                                Pass [] to auto-select all unnotified active/available listings.
 */
async function triggerSubscriberNotifications(listingIds = []) {
  try {
    // Resolve which listings to notify about
    let listingsToNotify;
    if (listingIds.length > 0) {
      const result = await pool.query(
        `SELECT * FROM listings WHERE id = ANY($1) AND status IN ('active', 'available') ORDER BY created_at DESC`,
        [listingIds]
      );
      listingsToNotify = result.rows;
    } else {
      const result = await pool.query(
        `SELECT * FROM listings WHERE status IN ('active', 'available') AND notification_sent = false ORDER BY created_at DESC`
      );
      listingsToNotify = result.rows;
    }

    if (listingsToNotify.length === 0) {
      console.log('[Notify] No eligible listings — skipping.');
      return { sent: 0, skipped: 0, listings_count: 0 };
    }

    // Fetch subscribers: active, not unsubscribed, not emailed in last 24h
    // Cap at NOTIFY_BATCH_LIMIT per event
    const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
    const subResult = await pool.query(
      `SELECT id, email FROM subscribers
       WHERE unsubscribed = false
       AND (last_notified_at IS NULL OR last_notified_at < $1)
       ORDER BY created_at ASC
       LIMIT $2`,
      [cutoff, NOTIFY_BATCH_LIMIT]
    );
    const subscribers = subResult.rows;

    if (subscribers.length === 0) {
      console.log('[Notify] No subscribers eligible — all unsubscribed or notified within 24h.');
      return { sent: 0, skipped: 0, listings_count: listingsToNotify.length };
    }

    const baseUrl = 'https://cutthelock.com';
    const subject = '🔓 New finds just dropped on Cut The Lock';

    // Build listing cards HTML
    const listingCardsHtml = listingsToNotify.map(l => {
      const photos = l.photos || [];
      const thumb = photos.length > 0
        ? `<img src="${escHtml(photos[0])}" alt="${escHtml(l.title)}" style="width:100%;height:160px;object-fit:cover;border-radius:6px 6px 0 0;display:block;">`
        : `<div style="width:100%;height:120px;background:#f0ede8;border-radius:6px 6px 0 0;display:flex;align-items:center;justify-content:center;font-size:2rem;">📦</div>`;
      const price = parseFloat(l.price).toFixed(2);
      return `
<div style="background:#fff;border:1px solid #e8e6e3;border-radius:8px;overflow:hidden;margin-bottom:16px;">
  <a href="${baseUrl}/listing/${l.id}?utm_source=email&utm_medium=newsletter&utm_campaign=new_listings" style="text-decoration:none;display:block;">
    ${thumb}
  </a>
  <div style="padding:14px 16px 16px;">
    <div style="font-weight:700;font-size:15px;color:#2C2B30;margin-bottom:4px;">${escHtml(l.title)}</div>
    <div style="font-size:13px;color:#888;margin-bottom:8px;text-transform:capitalize;">${escHtml(l.category)}${l.condition ? ' · ' + escHtml(l.condition) : ''}</div>
    <div style="display:flex;align-items:center;justify-content:space-between;">
      <span style="font-size:20px;font-weight:700;color:#C8593A;">$${price}</span>
      <a href="${baseUrl}/listing/${l.id}?utm_source=email&utm_medium=newsletter&utm_campaign=new_listings"
         style="display:inline-block;background:#C8593A;color:#fff;padding:8px 16px;border-radius:6px;text-decoration:none;font-size:13px;font-weight:600;">
        View Item →
      </a>
    </div>
  </div>
</div>`;
    }).join('');

    const listingTextLines = listingsToNotify.map(l =>
      `• ${l.title} — $${parseFloat(l.price).toFixed(2)} — ${baseUrl}/listing/${l.id}?utm_source=email&utm_medium=newsletter&utm_campaign=new_listings`
    ).join('\n');

    let sentCount = 0;
    let skippedCount = 0;

    for (const sub of subscribers) {
      const unsubUrl = `${baseUrl}/unsubscribe?email=${encodeURIComponent(sub.email)}`;

      const htmlBody = `
<div style="font-family:'Helvetica Neue',sans-serif;max-width:600px;margin:0 auto;color:#2C2B30;">
  <div style="background:#1a1918;padding:20px 24px;border-radius:8px 8px 0 0;text-align:center;">
    <div style="font-size:22px;font-weight:800;color:#C8A96E;letter-spacing:0.02em;">✂ CUT THE LOCK</div>
    <div style="color:rgba(255,255,255,0.7);font-size:12px;margin-top:4px;letter-spacing:0.05em;text-transform:uppercase;">New Finds Just Dropped</div>
  </div>
  <div style="background:#f8f7f6;padding:24px;border-radius:0 0 8px 8px;border:1px solid #e8e6e3;border-top:none;">
    <p style="margin:0 0 20px;font-size:15px;color:#4a4845;">
      Hey there — we just added ${listingsToNotify.length === 1 ? 'a new item' : listingsToNotify.length + ' new items'} to the marketplace. First come, first served.
    </p>
    ${listingCardsHtml}
    <div style="text-align:center;margin-top:20px;">
      <a href="${baseUrl}/listings?utm_source=email&utm_medium=newsletter&utm_campaign=new_listings"
         style="display:inline-block;background:#1a1918;color:#C8A96E;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:700;font-size:14px;letter-spacing:0.03em;">
        Browse All Listings →
      </a>
    </div>
    <div style="margin-top:28px;padding-top:20px;border-top:1px solid #e8e6e3;font-size:12px;color:#aaa;text-align:center;">
      You're getting this because you signed up at cutthelock.com.<br>
      <a href="${unsubUrl}" style="color:#aaa;">Unsubscribe</a>
    </div>
  </div>
</div>`;

      const textBody = [
        'New finds just dropped on Cut The Lock!',
        '',
        listingTextLines,
        '',
        `Browse all: ${baseUrl}/listings?utm_source=email&utm_medium=newsletter&utm_campaign=new_listings`,
        '',
        `You're getting this because you signed up at cutthelock.com.`,
        `Unsubscribe: ${unsubUrl}`
      ].join('\n');

      try {
        const sent = await sendEmailViaRelay({ to: sub.email, subject, textBody, htmlBody });
        if (sent) {
          await pool.query('UPDATE subscribers SET last_notified_at = NOW() WHERE id = $1', [sub.id]);
          sentCount++;
        } else {
          console.warn(`[Notify] Failed to send to ${sub.email}`);
          skippedCount++;
        }
      } catch (e) {
        console.warn(`[Notify] Error sending to ${sub.email}:`, e.message);
        skippedCount++;
      }
    }

    // Mark listings as notification_sent once at least one email went out
    if (sentCount > 0) {
      const ids = listingsToNotify.map(l => l.id);
      await pool.query('UPDATE listings SET notification_sent = true WHERE id = ANY($1)', [ids]);
    }

    console.log(`[Notify] Sent ${sentCount}/${subscribers.length} emails for ${listingsToNotify.length} listing(s)`);
    return { sent: sentCount, skipped: skippedCount, listings_count: listingsToNotify.length };
  } catch (err) {
    console.error('[Notify] triggerSubscriberNotifications error:', err);
    return { sent: 0, skipped: 0, listings_count: 0 };
  }
}

// Admin: notify subscribers about listings (manual trigger)
app.post('/api/admin/notify-subscribers', requireAdmin, async (req, res) => {
  try {
    const { listing_ids } = req.body;

    let listingIds = [];
    if (listing_ids && Array.isArray(listing_ids) && listing_ids.length > 0) {
      listingIds = listing_ids.map(id => parseInt(id, 10)).filter(id => !isNaN(id) && id > 0);
      if (listingIds.length === 0) return res.status(400).json({ success: false, message: 'No valid listing IDs.' });
    }

    const result = await triggerSubscriberNotifications(listingIds);

    if (result.listings_count === 0) {
      return res.json({ success: true, sent: 0, skipped: 0, message: 'No eligible listings to notify about.' });
    }
    if (result.sent === 0 && result.skipped === 0) {
      return res.json({ success: true, sent: 0, skipped: 0, message: 'No subscribers to notify (all unsubscribed or emailed within 24h).' });
    }

    res.json({
      success: true,
      sent: result.sent,
      skipped: result.skipped,
      listings_count: result.listings_count,
      message: `Notified ${result.sent} subscriber${result.sent !== 1 ? 's' : ''} about ${result.listings_count} listing${result.listings_count !== 1 ? 's' : ''}.`
    });
  } catch (err) {
    console.error('Error notifying subscribers:', err);
    res.status(500).json({ success: false, message: 'Failed to send notifications.' });
  }
});

// Admin: upload a photo to R2
app.post('/api/admin/upload-photo', requireAdmin, async (req, res) => {
  try {
    const { dataUrl, filename } = req.body;

    if (!dataUrl || typeof dataUrl !== 'string') {
      return res.status(400).json({ success: false, message: 'dataUrl is required.' });
    }

    // Parse data URL: data:<mimeType>;base64,<data>
    const match = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
    if (!match) {
      return res.status(400).json({ success: false, message: 'Invalid data URL format.' });
    }

    const mimeType = match[1];
    const base64Data = match[2];
    const buffer = Buffer.from(base64Data, 'base64');

    // Sanity check: max 8MB per photo
    if (buffer.length > 8 * 1024 * 1024) {
      return res.status(400).json({ success: false, message: 'Photo too large (max 8MB).' });
    }

    // Derive extension from MIME type
    const extMap = { 'image/jpeg': 'jpg', 'image/png': 'png', 'image/webp': 'webp', 'image/gif': 'gif', 'image/heic': 'heic' };
    const ext = extMap[mimeType] || 'jpg';
    const safeName = filename ? filename.replace(/[^a-zA-Z0-9._-]/g, '_') : `listing-${Date.now()}.${ext}`;

    try {
      const url = await uploadToR2(buffer, safeName, mimeType);
      console.log(`[R2] Uploaded photo: ${safeName} → ${url}`);
      res.json({ success: true, url });
    } catch (uploadErr) {
      console.warn('[R2] Upload failed, returning base64 fallback:', uploadErr.message);
      // Fallback: return the original dataUrl so the upload still "works"
      // (stored as base64 in DB as last resort)
      res.json({ success: true, url: dataUrl, fallback: true });
    }
  } catch (err) {
    console.error('Error uploading photo:', err);
    res.status(500).json({ success: false, message: 'Upload failed.' });
  }
});

// POST /api/admin/agreements/upload-doc — upload a signed agreement document (PDF/JPG/PNG) to R2
app.post('/api/admin/agreements/upload-doc', requireAdmin, async (req, res) => {
  try {
    const { dataUrl, filename } = req.body;
    if (!dataUrl || typeof dataUrl !== 'string') {
      return res.status(400).json({ success: false, message: 'dataUrl is required.' });
    }
    const match = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
    if (!match) {
      return res.status(400).json({ success: false, message: 'Invalid data URL format.' });
    }
    const mimeType = match[1];
    const base64Data = match[2];
    const buffer = Buffer.from(base64Data, 'base64');

    const allowed = ['image/jpeg', 'image/png', 'application/pdf'];
    if (!allowed.includes(mimeType)) {
      return res.status(400).json({ success: false, message: 'Only PDF, JPG, and PNG files are allowed.' });
    }
    if (buffer.length > 10 * 1024 * 1024) {
      return res.status(400).json({ success: false, message: 'File too large (max 10MB).' });
    }

    const extMap = { 'image/jpeg': 'jpg', 'image/png': 'png', 'application/pdf': 'pdf' };
    const ext = extMap[mimeType] || 'bin';
    const safeName = filename
      ? filename.replace(/[^a-zA-Z0-9._-]/g, '_')
      : `agreement-doc-${Date.now()}.${ext}`;

    try {
      const url = await uploadToR2(buffer, safeName, mimeType);
      console.log(`[R2] Uploaded agreement doc: ${safeName} → ${url}`);
      res.json({ success: true, url });
    } catch (uploadErr) {
      console.warn('[R2] Agreement doc upload failed, returning base64 fallback:', uploadErr.message);
      res.json({ success: true, url: dataUrl, fallback: true });
    }
  } catch (err) {
    console.error('Error uploading agreement doc:', err);
    res.status(500).json({ success: false, message: 'Upload failed.' });
  }
});

