// Helper: auto-detect and mark past-due arrangements
async function syncPastDueArrangements() {
  try {
    await pool.query(`
      UPDATE payment_arrangements
      SET status = 'Past Due', updated_at = NOW()
      WHERE status = 'Active'
        AND payoff_date < CURRENT_DATE
        AND balance_remaining > 0
    `);
  } catch (e) {
    console.error('[PA] syncPastDue error:', e.message);
  }
}

// Receipt number format: CTL-YYYYMMDD-XXXX (uppercase alphanumeric suffix)
// UNIQUE constraint on DB enforces no collisions; retry loop handles the rare case.
function generateReceiptNumber() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  const date = new Date().toISOString().slice(0, 10).replace(/-/g, '');
  let suffix = '';
  for (let i = 0; i < 4; i++) suffix += chars[Math.floor(Math.random() * chars.length)];
  return `CTL-${date}-${suffix}`;
}

// GET /api/admin/payment-arrangements — list with search/filter
app.get('/api/admin/payment-arrangements', requireAdmin, async (req, res) => {
  try {
    await syncPastDueArrangements();
    const { search, status } = req.query;
    const conditions = [];
    const params = [];

    if (search) {
      params.push(`%${search}%`);
      const idx = params.length;
      conditions.push(`(pa.invoice_number ILIKE $${idx} OR pa.customer_name ILIKE $${idx} OR pa.customer_email ILIKE $${idx})`);
    }
    if (status) {
      params.push(status);
      conditions.push(`pa.status = $${params.length}`);
    }

    const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

    const result = await pool.query(`
      SELECT pa.*,
             COALESCE(SUM(ap.amount), 0)::NUMERIC(10,2) AS total_paid
      FROM payment_arrangements pa
      LEFT JOIN arrangement_payments ap ON ap.arrangement_id = pa.id
      ${where}
      GROUP BY pa.id
      ORDER BY pa.created_at DESC
    `, params);

    res.json({ success: true, arrangements: result.rows });
  } catch (err) {
    console.error('Error fetching payment arrangements:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

// GET /api/admin/payment-arrangements/next-invoice — next CTL-XXXX number
app.get('/api/admin/payment-arrangements/next-invoice', requireAdmin, async (req, res) => {
  try {
    const result = await pool.query(`
      SELECT invoice_number FROM payment_arrangements ORDER BY id DESC LIMIT 1
    `);
    let nextNum = 1;
    if (result.rows.length > 0) {
      const last = result.rows[0].invoice_number;
      const m = last.match(/CTL-(\d+)/);
      if (m) nextNum = parseInt(m[1], 10) + 1;
    }
    const nextInvoice = 'CTL-' + String(nextNum).padStart(4, '0');
    res.json({ success: true, nextInvoice });
  } catch (err) {
    console.error('Error getting next invoice number:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

// POST /api/admin/payment-arrangements — create new
app.post('/api/admin/payment-arrangements', requireAdmin, async (req, res) => {
  try {
    const { customer_name, customer_email, customer_phone, total_amount, payoff_date, notes, agreement_file_url, description, payment_link } = req.body;

    if (!customer_name || !customer_email || !total_amount || !payoff_date) {
      return res.status(400).json({ success: false, message: 'customer_name, customer_email, total_amount, and payoff_date are required.' });
    }

    // Generate next invoice number (sequential, unique)
    const numResult = await pool.query(`SELECT invoice_number FROM payment_arrangements ORDER BY id DESC LIMIT 1`);
    let nextNum = 1;
    if (numResult.rows.length > 0) {
      const last = numResult.rows[0].invoice_number;
      const m = last.match(/CTL-(\d+)/);
      if (m) nextNum = parseInt(m[1], 10) + 1;
    }
    const invoice_number = 'CTL-' + String(nextNum).padStart(4, '0');

    const amt = parseFloat(total_amount);
    const result = await pool.query(`
      INSERT INTO payment_arrangements
        (invoice_number, customer_name, customer_email, customer_phone,
         total_amount, balance_remaining, payoff_date, notes, agreement_file_url,
         description, payment_link)
      VALUES ($1, $2, $3, $4, $5, $5, $6, $7, $8, $9, $10)
      RETURNING *
    `, [invoice_number, customer_name, customer_email, customer_phone || null,
      amt, payoff_date, notes || null, agreement_file_url || null,
      description || null, payment_link || null]);

    res.json({ success: true, arrangement: result.rows[0] });
  } catch (err) {
    console.error('Error creating payment arrangement:', err);
    if (err.code === '23505') {
      return res.status(409).json({ success: false, message: 'Invoice number conflict. Please try again.' });
    }
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

