// PATCH /api/admin/payment-arrangements/:id — update fields
app.patch('/api/admin/payment-arrangements/:id', requireAdmin, async (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    if (!id) return res.status(400).json({ success: false, message: 'Invalid ID' });

    const { customer_name, customer_email, customer_phone, total_amount, payoff_date, notes, agreement_file_url, status, description, payment_link } = req.body;

    const result = await pool.query(`
      UPDATE payment_arrangements
      SET
        customer_name      = COALESCE($1, customer_name),
        customer_email     = COALESCE($2, customer_email),
        customer_phone     = COALESCE($3, customer_phone),
        total_amount       = COALESCE($4, total_amount),
        payoff_date        = COALESCE($5, payoff_date),
        notes              = COALESCE($6, notes),
        agreement_file_url = COALESCE($7, agreement_file_url),
        status             = COALESCE($8, status),
        description        = COALESCE($9, description),
        payment_link       = COALESCE($10, payment_link),
        updated_at         = NOW()
      WHERE id = $11
      RETURNING *
    `, [
      customer_name || null,
      customer_email || null,
      customer_phone !== undefined ? (customer_phone || null) : null,
      total_amount ? parseFloat(total_amount) : null,
      payoff_date || null,
      notes !== undefined ? (notes || null) : null,
      agreement_file_url !== undefined ? (agreement_file_url || null) : null,
      status || null,
      description !== undefined ? (description || null) : null,
      payment_link !== undefined ? (payment_link || null) : null,
      id
    ]);

    if (!result.rows.length) return res.status(404).json({ success: false, message: 'Not found' });
    res.json({ success: true, arrangement: result.rows[0] });
  } catch (err) {
    console.error('Error updating payment arrangement:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

