// POST /api/admin/payment-arrangements/:id/payments — record a payment
app.post('/api/admin/payment-arrangements/:id/payments', requireAdmin, async (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    if (!id) return res.status(400).json({ success: false, message: 'Invalid ID' });

    const { amount, stripe_payment_id, notes, paid_at } = req.body;

    if (!amount || parseFloat(amount) <= 0) {
      return res.status(400).json({ success: false, message: 'amount must be a positive number.' });
    }

    const arrResult = await pool.query(`SELECT * FROM payment_arrangements WHERE id = $1`, [id]);
    if (!arrResult.rows.length) return res.status(404).json({ success: false, message: 'Arrangement not found' });

    const arr = arrResult.rows[0];
    if (arr.status === 'Cancelled') {
      return res.status(400).json({ success: false, message: 'Cannot record payment on a cancelled arrangement.' });
    }

    const paymentAmount = parseFloat(amount);

    // Generate unique receipt number — retry up to 5 times on collision (extremely rare)
    let payResult;
    for (let attempt = 0; attempt < 5; attempt++) {
      const receiptNum = generateReceiptNumber();
      try {
        payResult = await pool.query(`
          INSERT INTO arrangement_payments (arrangement_id, amount, stripe_payment_id, notes, paid_at, receipt_number)
          VALUES ($1, $2, $3, $4, COALESCE($5, NOW()), $6)
          RETURNING *
        `, [id, paymentAmount, stripe_payment_id || null, notes || null, paid_at || null, receiptNum]);
        break; // success
      } catch (insertErr) {
        // 23505 = unique_violation — try a new suffix
        if (insertErr.code === '23505' && attempt < 4) continue;
        throw insertErr;
      }
    }

    const newBalance = Math.max(0, parseFloat(arr.balance_remaining) - paymentAmount);
    const newStatus = newBalance <= 0 ? 'Paid Off' : (arr.status === 'Cancelled' ? arr.status : (new Date(arr.payoff_date) < new Date() ? 'Past Due' : 'Active'));

    await pool.query(`
      UPDATE payment_arrangements
      SET balance_remaining = $1, status = $2, updated_at = NOW()
      WHERE id = $3
    `, [newBalance, newStatus, id]);

    res.json({ success: true, payment: payResult.rows[0], new_balance: newBalance, new_status: newStatus });
  } catch (err) {
    console.error('Error recording payment:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

// DELETE /api/admin/payment-arrangements/:id/payments/:payId — void a payment
app.delete('/api/admin/payment-arrangements/:id/payments/:payId', requireAdmin, async (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const payId = parseInt(req.params.payId, 10);
    if (!id || !payId) return res.status(400).json({ success: false, message: 'Invalid ID' });

    const payResult = await pool.query(`
      SELECT * FROM arrangement_payments WHERE id = $1 AND arrangement_id = $2
    `, [payId, id]);
    if (!payResult.rows.length) return res.status(404).json({ success: false, message: 'Payment not found' });

    const refundAmount = parseFloat(payResult.rows[0].amount);
    await pool.query(`DELETE FROM arrangement_payments WHERE id = $1`, [payId]);

    // Restore balance (cap at total_amount)
    const arrResult = await pool.query(`
      UPDATE payment_arrangements
      SET balance_remaining = LEAST(total_amount, balance_remaining + $1), updated_at = NOW()
      WHERE id = $2
      RETURNING *
    `, [refundAmount, id]);

    if (arrResult.rows.length) {
      const arr = arrResult.rows[0];
      // If status was Paid Off but balance is now > 0, revert
      if (arr.status === 'Paid Off' && parseFloat(arr.balance_remaining) > 0) {
        const newStatus = new Date(arr.payoff_date) < new Date() ? 'Past Due' : 'Active';
        await pool.query(`UPDATE payment_arrangements SET status = $1, updated_at = NOW() WHERE id = $2`, [newStatus, id]);
      }
    }

    res.json({ success: true });
  } catch (err) {
    console.error('Error voiding payment:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

