app.get('/api/admin/invoices', requireAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 50, status } = req.query;
    const offset = (parseInt(page) - 1) * parseInt(limit);
    let conditions = [];
    let params = [];

    if (status) {
      params.push(status);
      conditions.push(`payment_status = $${params.length}`);
    }

    let query = 'SELECT * FROM invoices';
    let countQuery = 'SELECT COUNT(*) FROM invoices';

    if (conditions.length > 0) {
      query += ' WHERE ' + conditions.join(' AND ');
      countQuery += ' WHERE ' + conditions.join(' AND ');
    }

    query += ` ORDER BY id DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;

    const [result, countResult] = await Promise.all([
      pool.query(query, [...params, parseInt(limit), offset]),
      pool.query(countQuery, params)
    ]);

    res.json({ invoices: result.rows, total: parseInt(countResult.rows[0].count, 10) });
  } catch (err) {
    console.error('Error fetching invoices:', err);
    res.status(500).json({ error: 'Failed to fetch invoices' });
  }
});

app.get('/api/admin/invoices/next-number', requireAdmin, async (req, res) => {
  try {
    const result = await pool.query(`SELECT invoice_number FROM invoices ORDER BY id DESC LIMIT 1`);
    let nextNum = 1000;
    if (result.rows.length > 0) {
      const last = result.rows[0].invoice_number;
      const m = last.match(/CTL-(\d+)/);
      if (m) nextNum = parseInt(m[1], 10) + 1;
    }
    res.json({ success: true, nextNumber: 'CTL-' + String(nextNum).padStart(4, '0') });
  } catch (err) {
    res.status(500).json({ success: false });
  }
});

