// GET /api/pay/:invoice — look up an arrangement by invoice number (public, read-only)
// Returns only the fields needed for the customer portal — no PII beyond customer_name.
// Also returns receipt numbers so customers can confirm their payments were recorded.
app.get('/api/pay/:invoice', async (req, res) => {
  try {
    const invoice = req.params.invoice.toUpperCase().trim();
    const result = await pool.query(`
      SELECT
        id, invoice_number, customer_name, total_amount, balance_remaining,
        payoff_date, description, payment_link, status
      FROM payment_arrangements
      WHERE invoice_number = $1
    `, [invoice]);

    if (!result.rows.length) {
      return res.status(404).json({ success: false, message: 'Invoice not found' });
    }

    const arr = result.rows[0];

    // Fetch branded receipt numbers for this arrangement (most recent first)
    const receiptsResult = await pool.query(`
      SELECT receipt_number, amount, paid_at
      FROM arrangement_payments
      WHERE arrangement_id = $1
        AND receipt_number IS NOT NULL
      ORDER BY paid_at DESC
    `, [arr.id]);

    res.json({
      success: true,
      arrangement: {
        invoice_number: arr.invoice_number,
        customer_name: arr.customer_name,
        total_amount: parseFloat(arr.total_amount),
        balance_remaining: parseFloat(arr.balance_remaining),
        payoff_date: arr.payoff_date,
        description: arr.description,
        payment_link: arr.payment_link,
        status: arr.status,
        receipts: receiptsResult.rows.map(r => ({
          receipt_number: r.receipt_number,
          amount: parseFloat(r.amount),
          paid_at: r.paid_at
        }))
      }
    });
  } catch (err) {
    console.error('Error looking up invoice:', err);
    res.status(500).json({ success: false, message: 'Server error' });
  }
});

// Admin: AI-powered listing description generator
app.post('/api/admin/generate-description', requireAdmin, async (req, res) => {
  if (!openai) {
    return res.status(503).json({ success: false, message: 'OpenAI API key not configured. Set OPENAI_API_KEY in environment variables.' });
  }

  try {
    const {
      image_url,
      condition,
      category,
      sentimental,
      shipping_eligible,
      unit_origin,
      facility_name,
      facility_city,
      facility_state,
      notes
    } = req.body;

    // Build structured context for the prompt
    const formContext = [
      condition && `Condition: ${condition}`,
      category && `Category: ${category}`,
      unit_origin && `Unit: ${unit_origin}`,
      facility_name && `Facility: ${facility_name}`,
      (facility_city || facility_state) && `Location: ${[facility_city, facility_state].filter(Boolean).join(', ')}`,
      shipping_eligible ? 'Shipping available' : 'Local pickup only',
      sentimental && 'SENTIMENTAL ITEM — may have personal significance to original owner',
      notes && `Additional notes: ${notes}`
    ].filter(Boolean).join('\n');

    const systemPrompt = `You are a listing copywriter for Cut The Lock, a storage auction resale business. You write sharp, direct marketplace listings that sell fast.

Your voice:
- Bold first line: lead with the most valuable detail (brand, quantity, size)
- Emoji bullets for key features — visual scanners read these first
- Short punchy sentences — no fluff
- Mention estimated retail value when you can reasonably infer it ("New, these run $X+")
- Close with one hook line that creates urgency (scarcity, value, uniqueness)
- If the item is marked SENTIMENTAL: open with a recovery message first ("If this belongs to you or someone you know, contact us — we prioritize reuniting before resale."), then continue with standard listing format

Output format — return valid JSON only, no markdown fences:
{
  "suggested_title": "concise title under 80 chars",
  "suggested_description": "full markdown listing description",
  "suggested_price": null or a number
}`;

    const userPrompt = `Analyze the photo and generate a marketplace listing.

Form data:
${formContext}

Return ONLY the JSON object — no extra text, no code fences.`;

    // Build message content — include image if a valid http/https URL is provided
    const messageContent = [];
    if (image_url && /^https?:\/\//.test(image_url)) {
      messageContent.push({ type: 'image_url', image_url: { url: image_url, detail: 'high' } });
    }
    messageContent.push({ type: 'text', text: userPrompt });

    const completion = await openai.chat.completions.create({
      model: 'gpt-4o',
      max_tokens: 1000,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: messageContent }
      ]
    });

    const raw = completion.choices[0].message.content.trim();

    // Strip markdown code fences if model wraps in them despite instructions
    const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

    let parsed;
    try {
      parsed = JSON.parse(cleaned);
    } catch (parseErr) {
      console.error('[AI] Failed to parse response JSON:', raw);
      return res.status(500).json({ success: false, message: 'AI returned an unexpected format. Try again.' });
    }

    res.json({
      success: true,
      suggested_title: parsed.suggested_title || null,
      suggested_description: parsed.suggested_description || null,
      suggested_price: typeof parsed.suggested_price === 'number' ? parsed.suggested_price : null
    });
  } catch (err) {
    console.error('[AI] generate-description error:', err);
    const msg = err.status === 429 ? 'Rate limit reached — wait a moment and try again.'
      : err.status === 401 ? 'Invalid OpenAI API key.'
        : 'AI generation failed. Please try again.';
    res.status(500).json({ success: false, message: msg });
  }
});

// Generate a Stripe payment link for a listing.
// Uses Samantha's own Stripe account (STRIPE_SECRET_KEY) when configured;
// falls back to Polsia API if STRIPE_SECRET_KEY is absent.
// To enable: add STRIPE_SECRET_KEY=sk_live_… (or sk_test_…) as a Render env var.
app.post('/api/admin/generate-payment-link', requireAdmin, async (req, res) => {
  const { name, amount, description, listing_id } = req.body;
  if (!name || !amount || parseFloat(amount) <= 0) {
    return res.status(400).json({ success: false, message: 'Name and amount are required.' });
  }

  let linkUrl;

  if (STRIPE_SECRET_KEY) {
    // Direct Stripe API — no platform fee, full control
    try {
      const unitAmount = Math.round(parseFloat(amount) * 100); // dollars → cents
      const params = new URLSearchParams();
      params.append('line_items[0][price_data][currency]', 'usd');
      params.append('line_items[0][price_data][product_data][name]', String(name).slice(0, 250));
      if (description) params.append('line_items[0][price_data][product_data][description]', String(description).slice(0, 500));
      params.append('line_items[0][price_data][unit_amount]', String(unitAmount));
      params.append('line_items[0][quantity]', '1');
      params.append('after_completion[type]', 'redirect');
      params.append('after_completion[redirect][url]', 'https://cutthelock.com/thank-you');
      const payload = params.toString();
      const response = await new Promise((resolve, reject) => {
        const r = https.request({
          hostname: 'api.stripe.com',
          port: 443,
          path: '/v1/payment_links',
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
            'Content-Type': 'application/x-www-form-urlencoded',
            'Content-Length': Buffer.byteLength(payload)
          }
        }, (resp) => {
          let data = '';
          resp.on('data', chunk => { data += chunk; });
          resp.on('end', () => {
            try { resolve({ status: resp.statusCode, body: JSON.parse(data) }); }
            catch (e) { resolve({ status: resp.statusCode, body: data }); }
          });
        });
        r.on('error', reject);
        r.setTimeout(15000, () => { r.destroy(new Error('timeout')); });
        r.write(payload);
        r.end();
      });
      if (response.status >= 200 && response.status < 300 && response.body && response.body.url) {
        linkUrl = response.body.url;
      } else {
        const errMsg = (response.body && response.body.error && response.body.error.message) || 'Unknown Stripe error';
        return res.status(500).json({ success: false, message: `Stripe error: ${errMsg}` });
      }
    } catch (err) {
      return res.status(500).json({ success: false, message: 'Could not reach Stripe. Add the link manually.' });
    }
  } else if (PLATFORM_API_TOKEN) {
    // Fallback: external payment-link service — used until STRIPE_SECRET_KEY is set
    try {
      const payload = JSON.stringify({
        name: String(name).slice(0, 250),
        amount: parseFloat(amount),
        description: description || undefined,
        success_url: 'https://cutthelock.com/thank-you'
      });
      const apiUrl = new URL(`${STORAGE_BASE_URL}/api/stripe/payment-links`);
      const response = await new Promise((resolve, reject) => {
        const r = https.request({
          hostname: apiUrl.hostname,
          port: apiUrl.port || 443,
          path: apiUrl.pathname,
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(payload),
            'Authorization': `Bearer ${PLATFORM_API_TOKEN}`
          }
        }, (resp) => {
          let data = '';
          resp.on('data', chunk => { data += chunk; });
          resp.on('end', () => {
            try { resolve({ status: resp.statusCode, body: JSON.parse(data) }); }
            catch (e) { resolve({ status: resp.statusCode, body: data }); }
          });
        });
        r.on('error', reject);
        r.setTimeout(15000, () => { r.destroy(new Error('timeout')); });
        r.write(payload);
        r.end();
      });
      if (response.status >= 200 && response.status < 300) {
        const body = response.body;
        linkUrl = (body.payment_link && body.payment_link.url) || body.url || body.payment_url;
      }
      if (!linkUrl) {
        return res.status(500).json({ success: false, message: 'Payment link generation failed. Add the Stripe link manually.' });
      }
    } catch (err) {
      return res.status(500).json({ success: false, message: 'Could not generate payment link. Add the Stripe link manually.' });
    }
  } else {
    return res.status(503).json({
      success: false,
      message: 'No Stripe key configured. Add STRIPE_SECRET_KEY to Render environment variables (Settings → Environment).'
    });
  }

  if (listing_id) {
    await pool.query('UPDATE listings SET payment_link_url = $1 WHERE id = $2', [linkUrl, parseInt(listing_id)]);
  }
  return res.json({ success: true, url: linkUrl });
});

