// Purchase success page
app.get('/purchase-success', (req, res) => {
  // Redirect legacy Stripe success URL to the new /thank-you page, preserving all query params
  const qs = new URLSearchParams(req.query).toString();
  return res.redirect(302, '/thank-you' + (qs ? '?' + qs : ''));
});

// Legacy purchase-success stub — kept for reference (actual handler redirects above)
app.get('/purchase-success-legacy', (req, res) => {
  const listingId = parseInt(req.query.listing_id, 10);

  const html = pageShell('Purchase Confirmed', `
    <div class="success-page">
        <div class="success-card">
            <div class="success-check">
                <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <h1>Purchase Confirmed!</h1>
            <p class="order-msg">Thank you for your purchase. We'll be in touch with next steps — pickup details or shipping information depending on your chosen fulfillment option.</p>
            <div id="order-details"></div>
            <div class="success-actions">
                <a href="/listings" class="btn btn-primary">Continue Shopping</a>
                <a href="/" class="btn btn-secondary">Back to Home</a>
            </div>
        </div>
    </div>
    <script>
    (function() {
      var listingId = ${isNaN(listingId) ? 'null' : listingId};
      var sessionId = new URLSearchParams(window.location.search).get('session_id');
      var orderId = null;
      var fulfillmentMethod = 'pickup';
      var shippingInfo = null;

      // Fallback: read listing ID from sessionStorage (set by Buy Now button before Stripe redirect)
      if (!listingId) {
        try {
          var stored = sessionStorage.getItem('ctl_purchase_listing_id');
          if (stored) {
            listingId = parseInt(stored, 10) || null;
            sessionStorage.removeItem('ctl_purchase_listing_id');
          }
        } catch(e) {}
      }

      // Read pre-checkout order info (set for shipping orders)
      try {
        var orderStored = sessionStorage.getItem('ctl_order_info');
        if (orderStored) {
          var orderInfo = JSON.parse(orderStored);
          orderId = orderInfo.order_id || null;
          fulfillmentMethod = orderInfo.fulfillment || 'pickup';
          shippingInfo = orderInfo.shipping || null;
          sessionStorage.removeItem('ctl_order_info');
        }
      } catch(e) {}

      if (!listingId) return;

      // Mark listing as sold — pass order_id if we have one (shipping pre-checkout)
      fetch('/api/listings/' + listingId + '/mark-sold', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ session_id: sessionId || null, order_id: orderId || null })
      }).catch(function(e) { console.error('Error marking sold:', e); });

      // Load listing details for order summary
      fetch('/api/listings/' + listingId)
        .then(function(r) { return r.json(); })
        .then(function(data) {
          if (!data.success || !data.listing) return;
          var item = data.listing;
          var isShipping = fulfillmentMethod === 'shipping';
          var isLocalDelivery = fulfillmentMethod === 'local_delivery';
          var totalPaid = isShipping
            ? parseFloat(item.price) + parseFloat(item.shipping_price || 0)
            : isLocalDelivery
              ? parseFloat(item.price) + parseFloat(item.delivery_fee || 20)
              : parseFloat(item.price);
          // Meta Pixel — Purchase event with real price
          if (typeof fbq === 'function') {
            fbq('track', 'Purchase', { value: totalPaid || 0, currency: 'USD' });
          }
          var el = document.getElementById('order-details');
          var shippingRows = '';
          if (isShipping && shippingInfo) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">📦 Shipping</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Ship To</span>' +
                '<span class="order-summary-value" style="text-align:right;font-size:0.9em;">' +
                  escHtml(shippingInfo.name || '') + '<br>' +
                  escHtml(shippingInfo.address || '') + '<br>' +
                  escHtml(shippingInfo.city || '') + (shippingInfo.state ? ', ' + escHtml(shippingInfo.state) : '') + ' ' + escHtml(shippingInfo.zip || '') +
                '</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Shipping</span>' +
                '<span class="order-summary-value">+$' + parseFloat(item.shipping_price || 0).toFixed(2) + '</span>' +
              '</div>';
          } else if (isLocalDelivery && shippingInfo) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">🚚 Local Delivery</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Deliver To</span>' +
                '<span class="order-summary-value" style="text-align:right;font-size:0.9em;">' +
                  escHtml(shippingInfo.name || '') + '<br>' +
                  escHtml(shippingInfo.address || '') + '<br>' +
                  escHtml(shippingInfo.city || '') + (shippingInfo.state ? ', ' + escHtml(shippingInfo.state) : '') + ' ' + escHtml(shippingInfo.zip || '') +
                '</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Delivery Fee</span>' +
                '<span class="order-summary-value">+$' + parseFloat(item.delivery_fee || 20).toFixed(2) + '</span>' +
              '</div>';
          } else if (!isShipping && !isLocalDelivery) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">🏠 Local Pickup</span>' +
              '</div>';
          }
          el.innerHTML =
            '<div class="order-summary">' +
              '<div class="order-summary-title">Order Summary</div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Item</span><span class="order-summary-value">' + escHtml(item.title) + '</span></div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Category</span><span class="order-summary-value" style="text-transform:capitalize;">' + escHtml(item.category) + '</span></div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Condition</span><span class="order-summary-value" style="text-transform:capitalize;">' + escHtml(item.condition || 'Good') + '</span></div>' +
              shippingRows +
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);"><span class="order-summary-label">Total Paid</span><span class="order-summary-value price">$' + totalPaid.toFixed(2) + '</span></div>' +
            '</div>';
        })
        .catch(function() {});

      function escHtml(s) {
        if (!s) return '';
        var d = document.createElement('div');
        d.textContent = s;
        return d.innerHTML;
      }
    })();
    </script>
  `, '', {
    title: 'Purchase Confirmed | Cut The Lock',
    description: 'Your purchase has been confirmed. Thank you for shopping at Cut The Lock.',
    url: SEO_DEFAULTS.url + '/purchase-success'
  });

  res.type('html').send(html);
});

// Thank You page — post-purchase redirect target
app.get('/thank-you', (req, res) => {
  const listingId = parseInt(req.query.listing_id, 10);

  const html = pageShell('Thank You For Your Purchase', `
    <div class="success-page">
        <div class="success-card">
            <div class="success-check">
                <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <h1>You're All Set!</h1>
            <p class="order-msg">Your order was received and confirmed. We'll reach out shortly with pickup or shipping details.</p>
            <div id="order-details"></div>
            <div class="ty-recovery-nudge">
                <div class="ty-nudge-icon">🔍</div>
                <p class="ty-nudge-text">Did you have a storage unit that went to auction? We cut open units across Central Texas — your belongings may already be in our inventory.</p>
                <a href="/report-lost" class="btn btn-gold ty-nudge-btn">Submit a Recovery Claim</a>
            </div>
            <div class="success-actions">
                <a href="/listings" class="btn btn-primary">Continue Shopping</a>
                <a href="/" class="btn btn-secondary">Back to Home</a>
            </div>
        </div>
    </div>
    <style>
    .ty-recovery-nudge {
        background: rgba(212,160,23,0.07);
        border: 1px solid rgba(212,160,23,0.25);
        border-radius: 12px;
        padding: 24px;
        margin-bottom: 28px;
        text-align: center;
    }
    .ty-nudge-icon {
        font-size: 2rem;
        margin-bottom: 10px;
    }
    .ty-nudge-text {
        color: var(--text-muted);
        font-size: 0.95rem;
        line-height: 1.65;
        margin-bottom: 16px;
    }
    .btn-gold {
        background: linear-gradient(135deg, #D4A017 0%, #C9930B 100%);
        color: #0a0a0a;
        font-weight: 700;
        border: none;
        display: inline-block;
        padding: 12px 28px;
        border-radius: 8px;
        text-decoration: none;
        font-size: 0.95rem;
        letter-spacing: 0.02em;
        transition: opacity 0.2s;
    }
    .btn-gold:hover { opacity: 0.88; }
    .ty-nudge-btn { display: inline-block; }
    @media (max-width: 520px) {
        .success-actions { flex-direction: column; align-items: stretch; }
        .success-actions .btn { text-align: center; }
        .ty-nudge-btn { width: 100%; text-align: center; }
    }
    </style>
    <script>
    (function() {
      var listingId = ${isNaN(listingId) ? 'null' : listingId};
      var sessionId = new URLSearchParams(window.location.search).get('session_id');
      var orderId = null;
      var fulfillmentMethod = 'pickup';
      var shippingInfo = null;

      // Fallback: read listing ID from sessionStorage (set by Buy Now button before Stripe redirect)
      if (!listingId) {
        try {
          var stored = sessionStorage.getItem('ctl_purchase_listing_id');
          if (stored) {
            listingId = parseInt(stored, 10) || null;
            sessionStorage.removeItem('ctl_purchase_listing_id');
          }
        } catch(e) {}
      }

      // Read pre-checkout order info (set for shipping orders)
      try {
        var orderStored = sessionStorage.getItem('ctl_order_info');
        if (orderStored) {
          var orderInfo = JSON.parse(orderStored);
          orderId = orderInfo.order_id || null;
          fulfillmentMethod = orderInfo.fulfillment || 'pickup';
          shippingInfo = orderInfo.shipping || null;
          sessionStorage.removeItem('ctl_order_info');
        }
      } catch(e) {}

      if (!listingId) return;

      // Mark listing as sold — pass order_id if we have one (shipping pre-checkout)
      fetch('/api/listings/' + listingId + '/mark-sold', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ session_id: sessionId || null, order_id: orderId || null })
      }).catch(function(e) { console.error('Error marking sold:', e); });

      // Load listing details for order summary
      fetch('/api/listings/' + listingId)
        .then(function(r) { return r.json(); })
        .then(function(data) {
          if (!data.success || !data.listing) return;
          var item = data.listing;
          var isShipping = fulfillmentMethod === 'shipping';
          var isLocalDelivery = fulfillmentMethod === 'local_delivery';
          var totalPaid = isShipping
            ? parseFloat(item.price) + parseFloat(item.shipping_price || 0)
            : isLocalDelivery
              ? parseFloat(item.price) + parseFloat(item.delivery_fee || 20)
              : parseFloat(item.price);
          // Meta Pixel — Purchase event with real price
          if (typeof fbq === 'function') {
            fbq('track', 'Purchase', { value: totalPaid || 0, currency: 'USD' });
          }
          // Checkout completion event
          fetch('/api/events', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
              event_type: 'checkout_completed',
              metadata: { listing_id: listingId, stripe_session_id: sessionId || null },
              page_url: window.location.href
            })
          }).catch(function() {});
          var el = document.getElementById('order-details');
          var shippingRows = '';
          if (isShipping && shippingInfo) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">📦 Shipping</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Ship To</span>' +
                '<span class="order-summary-value" style="text-align:right;font-size:0.9em;">' +
                  escHtml(shippingInfo.name || '') + '<br>' +
                  escHtml(shippingInfo.address || '') + '<br>' +
                  escHtml(shippingInfo.city || '') + (shippingInfo.state ? ', ' + escHtml(shippingInfo.state) : '') + ' ' + escHtml(shippingInfo.zip || '') +
                '</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Shipping</span>' +
                '<span class="order-summary-value">+$' + parseFloat(item.shipping_price || 0).toFixed(2) + '</span>' +
              '</div>';
          } else if (isLocalDelivery && shippingInfo) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">🚚 Local Delivery</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Deliver To</span>' +
                '<span class="order-summary-value" style="text-align:right;font-size:0.9em;">' +
                  escHtml(shippingInfo.name || '') + '<br>' +
                  escHtml(shippingInfo.address || '') + '<br>' +
                  escHtml(shippingInfo.city || '') + (shippingInfo.state ? ', ' + escHtml(shippingInfo.state) : '') + ' ' + escHtml(shippingInfo.zip || '') +
                '</span>' +
              '</div>' +
              '<div class="order-summary-row">' +
                '<span class="order-summary-label">Delivery Fee</span>' +
                '<span class="order-summary-value">+$' + parseFloat(item.delivery_fee || 20).toFixed(2) + '</span>' +
              '</div>';
          } else if (!isShipping && !isLocalDelivery) {
            shippingRows =
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);">' +
                '<span class="order-summary-label">Fulfillment</span>' +
                '<span class="order-summary-value">🏠 Local Pickup</span>' +
              '</div>';
          }
          el.innerHTML =
            '<div class="order-summary">' +
              '<div class="order-summary-title">Order Summary</div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Item</span><span class="order-summary-value">' + escHtml(item.title) + '</span></div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Category</span><span class="order-summary-value" style="text-transform:capitalize;">' + escHtml(item.category) + '</span></div>' +
              '<div class="order-summary-row"><span class="order-summary-label">Condition</span><span class="order-summary-value" style="text-transform:capitalize;">' + escHtml(item.condition || 'Good') + '</span></div>' +
              shippingRows +
              '<div class="order-summary-row" style="margin-top:8px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.06);"><span class="order-summary-label">Total Paid</span><span class="order-summary-value price">$' + totalPaid.toFixed(2) + '</span></div>' +
            '</div>';
        })
        .catch(function() {});

      function escHtml(s) {
        if (!s) return '';
        var d = document.createElement('div');
        d.textContent = s;
        return d.innerHTML;
      }
    })();
    </script>
  `, '', {
    title: 'Thank You | Cut The Lock',
    description: 'Your order is confirmed. Thank you for shopping at Cut The Lock.',
    url: SEO_DEFAULTS.url + '/thank-you'
  });

  res.type('html').send(html);
});

