// SUBSCRIBERS (email capture / mailing list)
// ============================================================

// POST /api/subscribe — public endpoint, no auth required
app.post('/api/subscribe', async (req, res) => {
  try {
    const { email, source } = req.body || {};

    if (!email || typeof email !== 'string') {
      return res.status(400).json({ success: false, message: 'Email is required.' });
    }

    const cleaned = email.trim().toLowerCase();

    // Basic email format validation
    const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRe.test(cleaned)) {
      return res.status(400).json({ success: false, message: 'Please enter a valid email address.' });
    }

    const validSources = ['homepage', 'marketplace', 'story_page'];
    const src = validSources.includes(source) ? source : 'homepage';

    // Upsert — ON CONFLICT DO NOTHING so duplicates return success silently
    const subResult = await pool.query(
      `INSERT INTO subscribers (email, source)
       VALUES ($1, $2)
       ON CONFLICT (email) DO NOTHING
       RETURNING id`,
      [cleaned, src]
    );

    const isNew = subResult.rowCount > 0;

    // Always track the signup attempt (new or duplicate)
    const ipSub = (req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.socket?.remoteAddress || '');
    const uaSub = req.headers['user-agent'] || '';
    trackEvent('email_signup', {
      path: src === 'marketplace' ? '/listings' : '/',
      ip_hash: hashValue(ipSub),
      user_agent_hash: hashValue(uaSub),
      metadata: { email: cleaned, source: src, new_subscriber: isNew }
    });

    if (!isNew) {
      return res.json({ success: false, already_subscribed: true, message: "You\u2019re already on our list!" });
    }

    return res.json({ success: true });
  } catch (err) {
    console.error('Error saving subscriber:', err);
    return res.status(500).json({ success: false, message: 'Something went wrong. Please try again.' });
  }
});

// GET /api/subscribers — paginated active (non-unsubscribed) subscribers
// Used by Cold Outreach campaigns to stage promotional sends
app.get('/api/subscribers', async (req, res) => {
  try {
    const page = Math.max(1, parseInt(req.query.page, 10) || 1);
    const limit = Math.min(100, Math.max(1, parseInt(req.query.limit, 10) || 50));
    const offset = (page - 1) * limit;

    const countResult = await pool.query(
      'SELECT COUNT(*) AS total FROM subscribers WHERE unsubscribed = false'
    );
    const total = parseInt(countResult.rows[0].total, 10);

    const result = await pool.query(
      `SELECT id, email, source, created_at, unsubscribed, last_notified_at
       FROM subscribers
       WHERE unsubscribed = false
       ORDER BY created_at DESC
       LIMIT $1 OFFSET $2`,
      [limit, offset]
    );

    res.json({
      success: true,
      subscribers: result.rows,
      total,
      page,
      limit,
      total_pages: Math.ceil(total / limit)
    });
  } catch (err) {
    console.error('Error fetching subscribers:', err);
    res.status(500).json({ success: false, message: 'Failed to load subscribers.' });
  }
});

