// GET /unsubscribe?email=xxx — public unsubscribe link
app.get('/unsubscribe', async (req, res) => {
  const { email } = req.query;
  if (!email) {
    return res.status(400).send(`
      <html><body style="font-family:sans-serif;max-width:480px;margin:60px auto;text-align:center;color:#2C2B30;">
        <h2>Missing email</h2><p>This unsubscribe link is invalid.</p>
        <a href="${utmLink('https://cutthelock.com', '/', 'email', 'newsletter', 'unsubscribe')}" style="color:#C8593A;">← Back to Cut The Lock</a>
      </body></html>
    `);
  }
  try {
    const cleaned = String(email).trim().toLowerCase();
    const result = await pool.query(
      `UPDATE subscribers SET unsubscribed = true WHERE email = $1 RETURNING email`,
      [cleaned]
    );
    if (result.rows.length === 0) {
      // Email not in list — treat as success (don't leak subscriber status)
      return res.send(`
        <html><body style="font-family:sans-serif;max-width:480px;margin:60px auto;text-align:center;color:#2C2B30;">
          <div style="font-size:2rem;margin-bottom:16px;">✅</div>
          <h2>You're unsubscribed</h2>
          <p style="color:#888;">You won't receive any more emails from us.</p>
          <a href="${utmLink('https://cutthelock.com', '/', 'email', 'newsletter', 'unsubscribe')}" style="color:#C8593A;">← Back to Cut The Lock</a>
        </body></html>
      `);
    }
    console.log(`[Unsubscribe] ${cleaned} unsubscribed`);
    return res.send(`
      <html><head><meta charset="utf-8"><title>Unsubscribed — Cut The Lock</title>
      <meta name="viewport" content="width=device-width,initial-scale=1"></head>
      <body style="font-family:'Helvetica Neue',sans-serif;max-width:480px;margin:60px auto;padding:0 24px;text-align:center;color:#2C2B30;">
        <div style="font-size:2.5rem;margin-bottom:12px;">✂️</div>
        <h2 style="margin:0 0 8px;font-size:1.4rem;">You're unsubscribed</h2>
        <p style="color:#888;margin:0 0 24px;">We've removed <strong>${escHtml(cleaned)}</strong> from our list. No more emails.</p>
        <a href="${utmLink('https://cutthelock.com', '/listings', 'email', 'newsletter', 'unsubscribe')}" style="display:inline-block;background:#C8593A;color:#fff;padding:10px 24px;border-radius:6px;text-decoration:none;font-weight:600;font-size:14px;">Browse Items →</a>
        <div style="margin-top:24px;"><a href="${utmLink('https://cutthelock.com', '/', 'email', 'newsletter', 'unsubscribe')}" style="color:#aaa;font-size:13px;">← Cut The Lock Home</a></div>
      </body></html>
    `);
  } catch (err) {
    console.error('Error processing unsubscribe:', err);
    return res.status(500).send(`
      <html><body style="font-family:sans-serif;max-width:480px;margin:60px auto;text-align:center;color:#2C2B30;">
        <h2>Something went wrong</h2><p>Please try again or email us.</p>
      </body></html>
    `);
  }
});

