// PUT /api/admin/identity-verifications/:id — update admin fields
app.put('/api/admin/identity-verifications/:id', requireAdmin, async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!id || id < 1) return res.status(400).json({ success: false, message: 'Invalid ID' });
  try {
    const { verified_by, verification_notes, id_match_confirmed, verification_status, file_url } = req.body;
    const result = await pool.query(
      `UPDATE identity_verifications
       SET verified_by=$1, verification_notes=$2, id_match_confirmed=$3,
           verification_status=$4, file_url=$5, updated_at=NOW()
       WHERE id=$6
       RETURNING *`,
      [
        verified_by || null,
        verification_notes || null,
        id_match_confirmed === true,
        verification_status || 'pending',
        file_url || null,
        id
      ]
    );
    if (!result.rows.length) return res.status(404).json({ success: false, message: 'Not found' });
    res.json({ success: true, verification: result.rows[0] });
  } catch (err) {
    console.error('[IdentityVerification] Error updating verification:', err);
    res.status(500).json({ success: false, message: 'Failed to update verification.' });
  }
});

